$urls = @(
    "https://github.com/KAIST-Visual-AI-Group/APAP",
    "https://zju-vgi.github.io/RePerformer/",
    "https://github.com/mickare/Deformation-Transfer-for-Triangle-Meshes",
    "https://github.com/mattiaspaul/fastforward",
    "https://github.com/jiahao620/gaussreg",
    "https://github.com/Zjhthu/MAC",
    "https://github.com/Stable-SCore/Stable-SCore",
    "https://github.com/daidedou/diffumatch",
    "https://github.com/ZHLRJ/Non-Rigid-Shape-Correspondence",
    "https://echo-match.github.io"
)

foreach ($url in $urls) {
    try {
        $response = Invoke-WebRequest -Uri $url -UseBasicParsing -Method Head -TimeoutSec 10
        Write-Host "$url : $($response.StatusCode)"
    } catch {
        Write-Host "$url : $($_.Exception.Response.StatusCode.value__)"
    }
}
